const text = msg.status && msg.status.text;
node.warn('ws-out status: ' + JSON.stringify(msg.status));
if (text === 'connected' || text === 'common.status.connected') {
    return { payload: JSON.stringify({ message_id: 'init', command: 'start_listening' }) };
}
return null;

const text = msg.status && msg.status.text;
if (text === 'connected' || text === 'common.status.connected') {
    return { payload: JSON.stringify({ message_id: 'discover', command: 'get_nodes' }) };
}
return null;

try {
    msg.payload = JSON.parse(msg.payload);
} catch (e) {
    node.warn('matter: bad json: ' + e.message);
    return null;
}
return msg;

if (msg.payload && msg.payload.message_id && !msg.payload.event) {
    return [null, msg];
}
return [msg, null];

const p = msg.payload;
if (!p || !Array.isArray(p.result)) return null;
const first = p.result[0];
if (!first || typeof first.node_id !== 'number') return null;
global.set('matter_nodes', p.result);
global.set('matter_nodes_at', Date.now());

const aliveMsgs = [];
for (const n of p.result) {
    const attrs = n.attributes || {};
    const available = !!n.available;
    const nodeId = n.node_id;
    for (const key in attrs) {
        const m = key.match(/^(\d+)\/29\/0$/);
        if (!m) continue;
        const ep = Number(m[1]);
        if (ep === 0) continue;
        aliveMsgs.push({
            topic: `matter/${nodeId}/${ep}/_alive/0`,
            payload: available,
            matter: { nodeId: nodeId, endpoint: ep, cluster: '_alive', attribute: 0 }
        });
    }
}

return [aliveMsgs, { payload: { count: p.result.length, message_id: p.message_id, alive_emitted: aliveMsgs.length } }];

const data = msg.payload.data;
if (!Array.isArray(data) || data.length < 3) {
    node.warn('attribute_updated: oväntad data-form');
    return null;
}
const [nodeId, path, value] = data;
const [endpoint, cluster, attribute] = String(path).split('/');
return {
    topic: `matter/${nodeId}/${endpoint}/${cluster}/${attribute}`,
    payload: value,
    matter: { nodeId: nodeId, endpoint: Number(endpoint), cluster: Number(cluster), attribute: Number(attribute) }
};

const d = msg.payload && msg.payload.data;
if (!d || typeof d !== 'object') return null;

const nodeId = Number(d.node_id);
const ep = Number(d.endpoint_id);
const cluster = Number(d.cluster_id);
if (cluster !== 59) return null;

return {
    topic: `matter/${nodeId}/${ep}/59/_event/0`,
    payload: { event_id: d.event_id, data: d.data || {} },
    matter: { nodeId: nodeId, endpoint: ep, cluster: 59, attribute: '_event' }
};

const data = msg.payload && msg.payload.data;
if (!data || typeof data.node_id !== 'number') return null;

const nodes = global.get('matter_nodes') || [];
const idx = nodes.findIndex(n => n.node_id === data.node_id);
if (idx >= 0) nodes[idx] = data;
else nodes.push(data);
global.set('matter_nodes', nodes);
global.set('matter_nodes_at', Date.now());

const attrs = data.attributes || {};
const available = !!data.available;
const nodeId = data.node_id;
const aliveMsgs = [];
for (const key in attrs) {
    const m = key.match(/^(\d+)\/29\/0$/);
    if (!m) continue;
    const ep = Number(m[1]);
    if (ep === 0) continue;
    aliveMsgs.push({
        topic: `matter/${nodeId}/${ep}/_alive/0`,
        payload: available,
        matter: { nodeId: nodeId, endpoint: ep, cluster: '_alive', attribute: 0 }
    });
}
return [aliveMsgs];

// 2-output:
//  - output 1: WS payload till ws-out
//  - output 2: optimistisk syntetisk state-msg till matter:state (endast för write_attribute)
//
// Stodjer:
//   { kind: 'device_command' (default), nodeId, endpoint, cluster, command, args? }
//   { kind: 'write_attribute', nodeId, endpoint, cluster, attribute, value }
const p = msg.payload;
if (!p) {
    node.warn('build cmd: payload är tom');
    return null;
}

function msgId() {
    return `cmd-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
}

function buildOne(cmd) {
    if (!cmd || typeof cmd !== 'object') return [null, null];
    if (cmd.nodeId == null) {
        node.warn('build cmd: saknar nodeId i ' + JSON.stringify(cmd));
        return [null, null];
    }
    const kind = cmd.kind || 'device_command';

    if (kind === 'device_command') {
        if (cmd.endpoint == null || cmd.cluster == null || !cmd.command) {
            node.warn('build cmd: device_command saknar fields i ' + JSON.stringify(cmd));
            return [null, null];
        }
        const args = {
            node_id: Number(cmd.nodeId),
            endpoint_id: Number(cmd.endpoint),
            cluster_id: Number(cmd.cluster),
            command_name: String(cmd.command)
        };
        if (cmd.args !== undefined) args.payload = cmd.args;
        const json = JSON.stringify({ message_id: msgId(), command: 'device_command', args: args });
        return [{ payload: json }, null];
    }

    if (kind === 'write_attribute') {
        if (cmd.endpoint == null || cmd.cluster == null || cmd.attribute == null) {
            node.warn('build cmd: write_attribute saknar fields i ' + JSON.stringify(cmd));
            return [null, null];
        }
        const args = {
            node_id: Number(cmd.nodeId),
            attribute_path: `${cmd.endpoint}/${cmd.cluster}/${cmd.attribute}`,
            value: cmd.value
        };
        const json = JSON.stringify({ message_id: msgId(), command: 'write_attribute', args: args });
        // Optimistisk state-emit — vissa enheter (t.ex. Mill termostat) pushar inte attribute_updated på egna writes
        const stateMsg = {
            topic: `matter/${cmd.nodeId}/${cmd.endpoint}/${cmd.cluster}/${cmd.attribute}`,
            payload: cmd.value,
            matter: {
                nodeId: Number(cmd.nodeId),
                endpoint: Number(cmd.endpoint),
                cluster: Number(cmd.cluster),
                attribute: Number(cmd.attribute)
            }
        };
        return [{ payload: json }, stateMsg];
    }

    node.warn('build cmd: okänt kind ' + kind);
    return [null, null];
}

if (Array.isArray(p)) {
    for (const cmd of p) {
        const [wsMsg, stateMsg] = buildOne(cmd);
        if (wsMsg) node.send([wsMsg, null]);
        if (stateMsg) node.send([null, stateMsg]);
    }
    return null;
}

const [wsMsg, stateMsg] = buildOne(p);
return [wsMsg, stateMsg];

const flows = msg.payload;
if (!Array.isArray(flows)) {
    node.error('Bad /flows response: not an array');
    node.status({ fill: 'red', shape: 'dot', text: 'bad response' });
    return null;
}

const EH_ID = 'e228014191d14be6';
const eh = flows.find(n => n.id === EH_ID);
if (!eh) {
    node.error('hal2EventHandler ' + EH_ID + ' not found in /flows');
    node.status({ fill: 'red', shape: 'dot', text: 'eh not found' });
    return null;
}

eh.ingressLibrary = Array.isArray(eh.ingressLibrary) ? eh.ingressLibrary : [];
eh.egressLibrary = Array.isArray(eh.egressLibrary) ? eh.egressLibrary : [];

function genId() {
    return 'matter_lib_' + Math.random().toString(36).slice(2, 12);
}

const INGRESS_FNS = [
    { name: 'Pass-through', fn: 'return msg.payload;' },
    { name: 'Matter Level 0-254 → 0-100', fn: "const v = Number(msg.payload);
if (!isFinite(v)) return null;
return Math.round(Math.max(0, Math.min(254, v)) * 100 / 254);" },
    { name: 'Matter Mireds → CT %', fn: "// CT in mireds -> Kelvin -> 0-100% (100=2700K warmast, 0=6500K kallast)
const m = Number(msg.payload);
if (!isFinite(m) || m <= 0) return null;
const K = 1e6 / m;
const pct = Math.round(Math.max(0, Math.min(100, (6500 - K) / (6500 - 2700) * 100)));
return pct;" },
    { name: 'Matter Hue 0-254 → 0-360', fn: "const v = Number(msg.payload);
if (!isFinite(v)) return null;
return Math.round(Math.max(0, Math.min(254, v)) * 360 / 254);" },
    { name: 'Matter Compose Color H,S,B', fn: "const tm = String(msg.topic || '').match(/^matter\/\d+\/\d+\/(\d+)\/(\d+)$/);
if (!tm) return null;
const c = tm[1], a = tm[2];
const relevant = (c === '768' && (a === '0' || a === '1')) || (c === '8' && a === '0');
if (!relevant) return null;
const H = (typeof item['Hue'] === 'number') ? item['Hue'] : 0;
const S = (typeof item['Saturation'] === 'number') ? item['Saturation'] : 0;
const B = (typeof item['Brightness'] === 'number') ? item['Brightness'] : 0;
return `${H},${S},${B}`;" },
    { name: 'Matter milli → unit', fn: "const v = Number(msg.payload);
if (!isFinite(v)) return null;
return Math.round(v / 10) / 100;" },
    { name: 'Matter halfpercent → percent', fn: "const v = Number(msg.payload);
if (!isFinite(v)) return null;
return Math.round(v / 2);" },
    { name: 'Matter centi → unit', fn: "const v = Number(msg.payload);
if (!isFinite(v)) return null;
return v / 100;" },
    { name: 'Matter occupancy bit → bool', fn: "const v = Number(msg.payload);
if (!isFinite(v)) return null;
return (v & 1) === 1;" },
    { name: 'Matter illuminance → lux', fn: "const v = Number(msg.payload);
if (!isFinite(v)) return null;
return Math.round(Math.pow(10, (v - 1) / 10000));" },
    { name: 'Matter Switch event → press_type', fn: "const p = msg.payload;
if (!p || typeof p !== 'object') return null;
if (p.event_id === 4) return 'long';
if (p.event_id === 6) {
    const count = (p.data && p.data.totalNumberOfPressesCounted) || 1;
    if (count === 1) return 'single';
    if (count === 2) return 'double';
    if (count === 3) return 'triple';
    return `multi-${count}`;
}
return null;" },
    { name: 'Matter Thermostat SystemMode → string', fn: "// Cluster 513 attribute 28 (SystemMode enum) → human str
const v = Number(msg.payload);
if (!isFinite(v)) return null;
const MODES = { 0: 'off', 1: 'auto', 3: 'cool', 4: 'heat', 5: 'emergency_heat', 6: 'precooling', 7: 'fan_only', 8: 'dry', 9: 'sleep' };
return MODES[v] || `unknown-${v}`;" }
];

const EGRESS_FNS = [
    { name: 'Matter OnOff', fn: "const tm = String(msg.topic || '').match(/^matter\/(\d+)\/(\d+)/);
if (!tm) return null;
msg.payload = {
    nodeId: Number(tm[1]),
    endpoint: Number(tm[2]),
    cluster: 6,
    command: msg.payload ? 'On' : 'Off'
};
return msg;" },
    { name: 'Matter Level', fn: "const tm = String(msg.topic || '').match(/^matter\/(\d+)\/(\d+)/);
if (!tm) return null;
const pct = Math.max(0, Math.min(100, Number(msg.payload) || 0));
msg.payload = {
    nodeId: Number(tm[1]),
    endpoint: Number(tm[2]),
    cluster: 8,
    command: 'MoveToLevelWithOnOff',
    args: { level: Math.round(pct * 254 / 100), transitionTime: 0, optionsMask: 0, optionsOverride: 0 }
};
return msg;" },
    { name: 'Matter ColorTemp', fn: "const tm = String(msg.topic || '').match(/^matter\/(\d+)\/(\d+)/);
if (!tm) return null;
const pct = Math.max(0, Math.min(100, Number(msg.payload) || 0));
const K = 6500 - pct / 100 * (6500 - 2700);
const mireds = Math.max(153, Math.min(555, Math.round(1e6 / K)));
msg.payload = {
    nodeId: Number(tm[1]),
    endpoint: Number(tm[2]),
    cluster: 768,
    command: 'MoveToColorTemperature',
    args: { colorTemperatureMireds: mireds, transitionTime: 0, optionsMask: 0, optionsOverride: 0 }
};
return msg;" },
    { name: 'Matter HSB Color', fn: "const tm = String(msg.topic || '').match(/^matter\/(\d+)\/(\d+)/);
if (!tm) return null;
const nodeId = Number(tm[1]), endpoint = Number(tm[2]);
const parts = String(msg.payload || '').split(',').map(s => Number(String(s).trim()));
if (parts.length < 3 || !parts.every(isFinite)) {
    return null;
}
const [H, S, B] = parts;
const hue = Math.round(Math.max(0, Math.min(360, H)) * 254 / 360);
const sat = Math.round(Math.max(0, Math.min(100, S)) * 254 / 100);
const level = Math.round(Math.max(0, Math.min(100, B)) * 254 / 100);
msg.payload = [
    { nodeId, endpoint, cluster: 768, command: 'MoveToHueAndSaturation', args: { hue, saturation: sat, transitionTime: 0, optionsMask: 0, optionsOverride: 0 } },
    { nodeId, endpoint, cluster: 8, command: 'MoveToLevelWithOnOff', args: { level, transitionTime: 0, optionsMask: 0, optionsOverride: 0 } }
];
return msg;" },
    { name: 'Matter Thermostat Setpoint', fn: "// hal2 publishCommand pa 'target temperature' ger msg.payload = number (°C).
// Skriver BADE attr 17 (OccupiedHeatingSetpoint) OCH 18 (UnoccupiedHeatingSetpoint),
// 0.01 °C per LSB. Anledning: enheter varierar i vilken attr de respekterar.
// Mill m.fl. saknar Occupancy och respekterar bara 18; andra termostater 17.
// Build_cmd-fn:en i Controller-flowet hanterar arrays och skickar bada.
const tm = String(msg.topic || '').match(/^matter\/(\d+)\/(\d+)/);
if (!tm) return null;
const tempC = Number(msg.payload);
if (!isFinite(tempC)) return null;
const value = Math.round(Math.max(0, Math.min(100, tempC)) * 100);
const nodeId = Number(tm[1]);
const endpoint = Number(tm[2]);
msg.payload = [
    { kind: 'write_attribute', nodeId, endpoint, cluster: 513, attribute: 17, value },
    { kind: 'write_attribute', nodeId, endpoint, cluster: 513, attribute: 18, value }
];
return msg;" },
    { name: 'Matter Thermostat Mode', fn: "// hal2 publishCommand pa 'ac mode' ger msg.payload = str ('off'/'heat'/'auto'/'cool'/...).
// Skicka write_attribute till cluster 513 attr 28 (SystemMode enum).
const tm = String(msg.topic || '').match(/^matter\/(\d+)\/(\d+)/);
if (!tm) return null;
const mode = String(msg.payload || '').toLowerCase();
const MODE_MAP = { 'off': 0, 'auto': 1, 'cool': 3, 'heat': 4, 'emergency_heat': 5, 'precooling': 6, 'fan_only': 7, 'dry': 8, 'sleep': 9 };
const value = MODE_MAP[mode];
if (value === undefined) {
    node.warn('Matter Thermostat Mode: okant mode ' + JSON.stringify(msg.payload));
    return null;
}
msg.payload = {
    kind: 'write_attribute',
    nodeId: Number(tm[1]),
    endpoint: Number(tm[2]),
    cluster: 513,
    attribute: 28,
    value: value
};
return msg;" }
];

const ingressIdx = new Map(eh.ingressLibrary.map((f, i) => [f.name, i]));
const egressIdx = new Map(eh.egressLibrary.map((f, i) => [f.name, i]));

const added = [];
const updated = [];

for (const f of INGRESS_FNS) {
    const i = ingressIdx.get(f.name);
    if (i === undefined) {
        eh.ingressLibrary.push({ id: genId(), name: f.name, fn: f.fn });
        added.push('ingress: ' + f.name);
    } else if (eh.ingressLibrary[i].fn !== f.fn) {
        eh.ingressLibrary[i].fn = f.fn;
        updated.push('ingress: ' + f.name);
    }
}
for (const f of EGRESS_FNS) {
    const i = egressIdx.get(f.name);
    if (i === undefined) {
        eh.egressLibrary.push({ id: genId(), name: f.name, fn: f.fn });
        added.push('egress: ' + f.name);
    } else if (eh.egressLibrary[i].fn !== f.fn) {
        eh.egressLibrary[i].fn = f.fn;
        updated.push('egress: ' + f.name);
    }
}

if (added.length === 0 && updated.length === 0) {
    node.warn('Library: inga andringar (alla fns aktuella)');
    node.status({ fill: 'grey', shape: 'dot', text: 'no changes' });
    return null;
}

const summary = [...added.map(s => '+' + s), ...updated.map(s => '~' + s)];
node.warn('Library: ' + summary.length + ' fn(s):
  ' + summary.join('
  '));
node.status({ fill: 'green', shape: 'dot', text: `+${added.length} ~${updated.length}` });

