function buildItem(spec, errors) {
    const ep = spec.endpoint, c = spec.cluster, a = spec.attr;
    const ingressId = resolveLibFn(spec.ingress, ingressLib);
    const egressId = spec.egress ? resolveLibFn(spec.egress, egressLib) : null;
    if (spec.ingress && !ingressId) errors.push(`ingress fn '${spec.ingress}' (item '${spec.name}')`);
    if (spec.egress && !egressId) errors.push(`egress fn '${spec.egress}' (item '${spec.name}')`);
    const filterValue = spec.filterValue || `/${c}/${a}`;
    const item = {
        name: spec.name,
        id: spec.id,
        topicFilters: [{ field: 'topic', matchType: 'StrEnd', value: filterValue }],
        topicFilterMode: 'and',
        topicSuffix: spec.egress ? `./${ep}/${c}/${a}` : '',
        type: spec.readOnly ? 'status' : 'both',
        haType: spec.haType || '',
        ingress: ingressId,
        egress: egressId,
        notes: spec.notes || `Endpoint ${ep}, cluster ${c} attribute ${a}`,
        output: '1',
        history: spec.history !== undefined ? spec.history : true,
        historyAllUpdates: false
    };
    if (spec.readOnly) item.readOnly = true;
    return item;
}

function buildAliveItem(errors) {
    const ingressId = resolveLibFn('Pass-through', ingressLib);
    if (!ingressId) errors.push(`ingress fn 'Pass-through' (item 'Alive')`);
    return {
        name: 'Alive',
        id: '1',
        topicFilters: [{ field: 'topic', matchType: 'StrEnd', value: '/_alive/0' }],
        topicFilterMode: 'and',
        topicSuffix: '',
        readOnly: true,
        type: 'status',
        ingress: ingressId,
        egress: ''
    };
}

function buildThingType(id, zTab, errors) {
    const tpl = TT_TEMPLATES[id];
    if (!tpl) return null;
    const items = tpl.items.map(s => buildItem(s, errors));
    items.push(buildAliveItem(errors));
    const aliveIngressId = resolveLibFn('Pass-through', ingressLib);
    return {
        id: id,
        type: 'hal2ThingType',
        z: zTab,
        name: tpl.name,
        contextStore: 'filesystem',
        nodestatus: tpl.nodestatus,
        nodestatusType: 'str',
        statusFn: "return '';",
        items: items,
        attributes: [],
        ingress: [],
        egress: [],
        thingStatus: true,
        thingCommand: true,
        thingOutput: true,
        hbCheck: true,
        hbType: 'lwt',
        hbTTL: '',
        hbLWT: aliveIngressId,
        hbFilters: [{ field: 'topic', matchType: 'StrEnd', value: '/_alive/0' }],
        hbFilterMode: 'and',
        hbFilterVal: '',
        hbFilterType: '',
        hbPropVal: 'payload',
        hbPropType: 'msg',
        filterFunction: '0',
        outputs: '1'
    };
}

function computeShape(matterNode) {
    const attrs = matterNode.attributes || {};
    // Samla device types per endpoint (Set så duplicat collapsar)
    const epDts = new Map();
    for (const key in attrs) {
        const m = key.match(/^(\d+)\/29\/0$/);
        if (!m) continue;
        const ep = Number(m[1]);
        if (ep === 0) continue;
        const dtList = attrs[key];
        if (!Array.isArray(dtList)) continue;
        if (!epDts.has(ep)) epDts.set(ep, new Set());
        for (const dt of dtList) {
            const t = dt && dt['0'];
            if (typeof t !== 'number') continue;
            if (AUXILIARY_DEVICE_TYPES.has(t)) continue;
            epDts.get(ep).add(t);
        }
    }
    // METERABLE: dessa DTs får '+meter' när inline-metering finns på endpointen
    // (antingen via 1296 i samma DT-lista eller cluster 144 utan 1296 deklarerat).
    const METERABLE = new Set([257, 266]);
    const eps = [];
    for (const [ep, types] of epDts) {
        if (types.size === 0) continue;
        const has1296 = types.has(1296);
        const hasCluster144 = attrs[`${ep}/144/0`] !== undefined;
        const mainTypes = [...types].filter(t => t !== 1296);
        if (mainTypes.length === 0 && has1296) {
            // Endpoint endast 1296 (separat metering-endpoint, t.ex. matter_metered_plug)
            eps.push([ep, 1296]);
            continue;
        }
        for (const t of mainTypes) {
            const hasMeter = METERABLE.has(t) && (has1296 || hasCluster144);
            eps.push([ep, hasMeter ? `${t}+meter` : t]);
        }
    }
    // Root-endpoint-metering (cluster 144 på endpoint 0) som egen shape-komponent
    if (attrs['0/144/0'] !== undefined) eps.push([0, 'meter']);
    eps.sort((a, b) => {
        if (a[0] !== b[0]) return a[0] - b[0];
        return String(a[1]).localeCompare(String(b[1]));
    });
    return eps.map(([ep, dt]) => `(${ep},${dt})`).join(',');
}

const LINK_OUT_ID = 'matter_things_cmd_out';
const STATE_IN_ID = 'matter_things_state_in';
const EVENT_HANDLER_ID = 'e228014191d14be6';

const existingPrefixes = new Set();
let existingThingCount = 0;
for (const n of flowJson.nodes) {
    if (n.type === 'hal2Thing' && n.topicPrefix) {
        existingPrefixes.add(n.topicPrefix);
        existingThingCount++;
    }
}
const existingTTIds = new Set(flowJson.configs.filter(c => c.type === 'hal2ThingType').map(c => c.id));

const newNodes = [];
const newConfigs = [];
const skipped = [];

for (const mn of matterNodes) {
    if (typeof mn.node_id !== 'number') continue;
    const shape = computeShape(mn);
    if (!shape) {
        skipped.push({ node_id: mn.node_id, reason: 'no endpoints with device_type' });
        continue;
    }

    const ttId = SHAPE_TO_TT[shape];
    if (!ttId) {
        skipped.push({ node_id: mn.node_id, shape: shape, reason: 'no ThingType for node-shape' });
        continue;
    }

    const topicPrefix = `matter/${mn.node_id}`;
    if (existingPrefixes.has(topicPrefix)) continue;

    if (!existingTTIds.has(ttId)) {
        const errors = [];
        const newTT = buildThingType(ttId, flowJson.id, errors);
        if (!newTT) {
            skipped.push({ node_id: mn.node_id, shape: shape, reason: `no template for ThingType '${ttId}'` });
            continue;
        }
        if (errors.length) {
            skipped.push({ node_id: mn.node_id, shape: shape, reason: `unresolved library fns: ${errors.join(', ')}` });
            continue;
        }
        newConfigs.push(newTT);
        existingTTIds.add(ttId);
    }

    const thingId = `matter_thing_${mn.node_id}`;
    const attrs = mn.attributes || {};
    const vendor = String(attrs['0/40/1'] || '').trim();
    const product = String(attrs['0/40/3'] || '').trim();
    const name = (vendor || product) ? `${vendor} ${product}`.trim() : `Matter ${mn.node_id}`;

    newNodes.push({
        id: thingId,
        type: 'hal2Thing',
        z: flowJson.id,
        eventHandler: EVENT_HANDLER_ID,
        thingType: ttId,
        name: name,
        attributes: [],
        topicFilter: `${topicPrefix}/#`,
        topicFilterType: 'mqtt',
        topicPrefix: topicPrefix,
        notes: `Auto-genererad ${new Date().toISOString()}. shape=${shape}.`,
        outputs: 1,
        x: 320,
        y: 200 + 80 * (existingThingCount + newNodes.length),
        wires: [[LINK_OUT_ID]]
    });
}

if (newNodes.length === 0 && newConfigs.length === 0) {
    const txt = `no changes (existing=${existingThingCount}, skipped=${skipped.length})`;
    node.status({ fill: 'grey', shape: 'dot', text: txt });
    if (skipped.length) node.warn(`Sync skipped: ${JSON.stringify(skipped)}`);
    return null;
}

const stateIn = flowJson.nodes.find(n => n.id === STATE_IN_ID);
if (stateIn && newNodes.length > 0) {
    if (!Array.isArray(stateIn.wires)) stateIn.wires = [[]];
    if (!Array.isArray(stateIn.wires[0])) stateIn.wires[0] = [];
    for (const n of newNodes) {
        if (!stateIn.wires[0].includes(n.id)) stateIn.wires[0].push(n.id);
    }
}

flowJson.nodes.push(...newNodes);
flowJson.configs.push(...newConfigs);

const summary = `+${newNodes.length} thing(s)` + (newConfigs.length ? `, +${newConfigs.length} ThingType(s)` : '');
node.status({ fill: 'green', shape: 'dot', text: summary });
node.warn(`Sync: ${summary}. New Things: ${newNodes.map(n => `${n.name} [${n.id}]`).join(', ') || '—'}. New ThingTypes: ${newConfigs.map(c => c.id).join(', ') || '—'}.`);
if (skipped.length) node.warn(`Sync skipped: ${JSON.stringify(skipped)}`);

msg.payload = flowJson;
msg.url = 'http://127.0.0.1:1880/flow/7d7d6362013173c3';
msg.method = 'PUT';
msg.headers = { 'Content-Type': 'application/json' };
return msg;
